-- Program: Social Walking Group
-- Category: Social/Community Fitness -> social_fitness
-- Priority: Med
-- Durations: [4, 8], Sessions: [3, 4, 5]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Social Walking Group',
    'Walking-based fitness program combining brisk walks with bodyweight exercises in parks',
    'social_fitness',
    'all_levels',
    8,
    5,
    'full_body',
    ARRAY['Build functional strength', 'Improve body control']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Social Walking Group - 4w 3x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Social Walking Group - 4w 3x/wk',
    'social_fitness',
    3,
    60,
    ARRAY['Build functional strength', 'Improve body control']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Social Walking Group'
ON CONFLICT DO NOTHING;

